import{_ as e,o as r,c as a,ak as p}from"./chunks/framework.571fwNe4.js";const f=JSON.parse('{"title":"关于","description":"","frontmatter":{"title":"关于","date":"2024-02-08T17:08:37.000Z","page_cover":"https://s2.loli.net/2024/02/08/iCncju5LIHmWaYf.png","page_cover_height":300,"top_img":"https://s2.loli.net/2024/02/09/uTcSxbC6kRMPfvj.jpg"},"headers":[],"relativePath":"about.md","filePath":"about.md"}'),o={name:"about.md"};function n(l,t,s,i,_,c){return r(),a("div",null,[...t[0]||(t[0]=[p('<p>已经记不清这是第几次写 About 了。</p><p>一是人总是在变，明明才过去几个月，就觉得自己和以前亲手写出的自述天差地别。二是博客也总是在变，像一架破车，断断续续地走在路上。明明才过去几年，博客却数次停启。</p><p>现在，请允许我再写一次吧。</p><p>这里是 Parolluvia 的博客，我喜欢将其称为 “Parolluvia 的旅馆“。希望可以为远道而来的客人带来一些慰藉和启发。</p><p>关于我自己，现在(2024.2)是一枚高三学生。退役 OIer，半个写作爱好者。</p><p>最初是2017年左右，入坑 Python，作为爱好。2018年，接触 C++，创立了自己的第一个 GitHub 账号（虽然已经丢失了）。但由于那时能力有限及学业紧张，没有机会深入学习。本有机会在初中就接触 OI，因为一些客观原因擦肩而过。</p><p>就这样跌跌撞撞地到了2020年初，疫情。大量的时间被富余出来，于是被我全数投在写代码上。</p><p>于是，我学了一点 JavaScript，接触了几个框架，便疯狂地投身于社区项目上。我和网友 momen、PaperDragon 一起创立了 <a href="https://bbs.spark-app.store/" target="_blank" rel="noreferrer">DOSU社区</a>，后来和 shenmo 的 Spark Store 回合，变成了今天的 <a href="https://www.spark-app.store/" target="_blank" rel="noreferrer">Spark Store</a>。</p><p>现在看来，真的是年少轻狂。</p><p>后来就开学了，好在假期的不务正业似乎并没有对学习造成什么影响。再后来，我上了高中，正式走进了 OI 的大门。然后便是常规的停课、外出集训、比赛……不得不承认，在这学竞赛的两年里，我学到了很多。感谢同行的老师和同学们。</p><p>再后来，我就在一个阴雨天的傍晚，对着乌蓝的窗子，写下这篇 About。</p><p>言归正传。这个博客里，我会写一写碎笔、小诗，也会发表一些议论、观点。未来，可能会有一些技术性的内容吧。看未来的路怎么走了。</p><p>希望你能喜欢。</p><p>最后，附上自己的联系方式：</p><p>邮箱： <a href="mailto:qingdkj@outlook.com" target="_blank" rel="noreferrer">qingdkj@outlook.com</a></p><p>GitHub: <a href="https://github.com/qingdkj" target="_blank" rel="noreferrer">Parolluvia(qingdkj)</a></p>',16)])])}const k=e(o,[["render",n]]);export{f as __pageData,k as default};
